 1	import * as React from 'react';
 2	import { List } from '@patternfly/react-core';
 3	import { ComponentStatus, Status } from '../../types/IstioStatus';
 4	import { IstioComponentStatus } from './IstioComponentStatus';
 5	import { kialiStyle } from 'styles/StyleUtils';
 6	import { useKialiTranslation } from 'utils/I18nUtils';
 7	
 8	type Props = {
 9	  cluster: string;
10	  status: ComponentStatus[];
11	};
12	
13	const listStyle = kialiStyle({
14	  paddingLeft: 0,
15	  marginTop: 0,
16	  marginLeft: 0
17	});
18	
19	export const IstioStatusList: React.FC<Props> = (props: Props) => {
20	  const { t } = useKialiTranslation();
21	
22	  const nonhealthyComponents = (): ComponentStatus[] => {
23	    return props.status.filter((c: ComponentStatus) => c.status !== Status.Healthy);
24	  };
25	
26	  const coreComponentsStatus = (): ComponentStatus[] => {
27	    return nonhealthyComponents().filter((s: ComponentStatus) => s.isCore);
28	  };
29	
30	  const addonComponentsStatus = (): ComponentStatus[] => {
31	    return nonhealthyComponents().filter((s: ComponentStatus) => !s.isCore);
32	  };
33	
34	  const renderComponentList = (): React.ReactNode => {
35	    const groups = {
36	      core: coreComponentsStatus,
37	      addon: addonComponentsStatus
38	    };
39	
40	    return ['core', 'addon'].map((group: string) => {
41	      return (
42	        <React.Fragment key={`status-${group}`}>
43	          {groups[group]().map((status: ComponentStatus) => {
44	            return <IstioComponentStatus key={`status-${group}-${status.name}`} componentStatus={status} />;
45	          })}
46	        </React.Fragment>
47	      );
48	    });
49	  };
50	
51	  return (
52	    <List id="istio-status" aria-label={t('Istio Component List')} className={listStyle}>
53	      {renderComponentList()}
54	    </List>
55	  );
56	};

