 1	import * as React from 'react';
 2	import { ComponentStatus, Status, statusMsg } from '../../types/IstioStatus';
 3	import { PFColors } from '../Pf/PfColors';
 4	import {
 5	  CheckCircleIcon,
 6	  ExclamationCircleIcon,
 7	  ExclamationTriangleIcon,
 8	  MinusCircleIcon
 9	} from '@patternfly/react-icons';
10	import { Split, SplitItem } from '@patternfly/react-core';
11	import { IconProps, createIcon } from 'config/KialiIcon';
12	import { kialiStyle } from 'styles/StyleUtils';
13	import { useKialiTranslation } from 'utils/I18nUtils';
14	
15	type Props = {
16	  componentStatus: ComponentStatus;
17	};
18	
19	const ErrorCoreComponent: IconProps = {
20	  color: PFColors.Danger,
21	  icon: ExclamationCircleIcon
22	};
23	
24	const ErrorAddonComponent: IconProps = {
25	  color: PFColors.Warning,
26	  icon: ExclamationTriangleIcon
27	};
28	
29	const NotReadyComponent: IconProps = {
30	  color: PFColors.Info,
31	  icon: MinusCircleIcon
32	};
33	
34	const SuccessComponent: IconProps = {
35	  color: PFColors.Success,
36	  icon: CheckCircleIcon
37	};
38	
39	// Mapping Valid-Core to Icon representation.
40	const validToIcon: { [valid: string]: IconProps } = {
41	  'false-false': ErrorAddonComponent,
42	  'false-true': ErrorCoreComponent,
43	  'true-false': SuccessComponent,
44	  'true-true': SuccessComponent
45	};
46	
47	const splitItemStyle = kialiStyle({
48	  textAlign: 'left'
49	});
50	
51	export const IstioComponentStatus: React.FC<Props> = (props: Props) => {
52	  const { t } = useKialiTranslation();
53	
54	  const renderIcon = (status: Status, isCore: boolean): React.ReactNode => {
55	    let compIcon = validToIcon[`${status === Status.Healthy}-${isCore}`];
56	
57	    if (status === Status.NotReady) {
58	      compIcon = NotReadyComponent;
59	    }
60	
61	    compIcon.className = kialiStyle({
62	      marginTop: '0.25rem'
63	    });
64	
65	    return createIcon(compIcon);
66	  };
67	
68	  const renderCells = (): React.ReactNode => {
69	    const comp = props.componentStatus;
70	
71	    return [
72	      <Split key={`cell-status-icon-${comp.name}`} hasGutter={true} className={splitItemStyle}>
73	        <SplitItem style={{ paddingLeft: '0.5rem' }}>
74	          {renderIcon(props.componentStatus.status, props.componentStatus.isCore)}
75	        </SplitItem>
76	        <SplitItem isFilled={true}>{comp.name}</SplitItem>
77	        <SplitItem>{t(statusMsg[comp.status])}</SplitItem>
78	      </Split>
79	    ];
80	  };
81	
82	  return <>{renderCells()}</>;
83	};

